import{_ as t,o as a,c as n,ac as o}from"./chunks/framework.DnBnwVZk.js";const p=JSON.parse('{"title":"Netty 基本组件","description":"","frontmatter":{"date":"2020-06-04T00:00:00.000Z","categories":["Netty"],"tags":["Netty"],"publish":false},"headers":[],"relativePath":"views/netty/BasicComponents.md","filePath":"views/netty/BasicComponents.md","lastUpdated":1775803235000}'),l={name:"views/netty/BasicComponents.md"};function d(r,e,i,h,c,s){return a(),n("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1591228800000"},[...e[0]||(e[0]=[o('<h1 id="netty-基本组件" tabindex="-1">Netty 基本组件 <a class="header-anchor" href="#netty-基本组件" aria-label="Permalink to &quot;Netty 基本组件&quot;">​</a></h1><ul><li>Channel: 抽象的IO事件处理接口，read/write</li><li>ChannelHandler: 数据处理接口</li><li>ChannelPipeline: 串联ChannelHandler</li><li>EventLoop:</li><li>ChannelFuture: 配合ChannelFutureListener实现异步回调</li><li>Bootstrap: 用来初始化，分为ServerBootstrap和Bootstrap(客户端用)</li></ul><h2 id="为什么netty管理channel不需要多线程同步" tabindex="-1">为什么Netty管理Channel不需要多线程同步 <a class="header-anchor" href="#为什么netty管理channel不需要多线程同步" aria-label="Permalink to &quot;为什么Netty管理Channel不需要多线程同步&quot;">​</a></h2><p>Channel-EventLoop是一一对应的，而EventLoop会绑定唯一的Thread</p><h2 id="channelhandler" tabindex="-1">ChannelHandler <a class="header-anchor" href="#channelhandler" aria-label="Permalink to &quot;ChannelHandler&quot;">​</a></h2><h3 id="分类" tabindex="-1">分类 <a class="header-anchor" href="#分类" aria-label="Permalink to &quot;分类&quot;">​</a></h3><p>分为ChannelInboundHandler和ChannelOutboundHanlder两种，Netty对此有一系列包装，提供了<code>ChannelInboundHandlerAdapter</code>和<code>ChannelOutboundHandlerAdapter</code>两套抽象类，实际使用时，可以继承两种实现或其子类来进行进一步的扩展。</p><blockquote><p>Inbound: Client -&gt; Server Outbound: Server -&gt; Client</p></blockquote><h3 id="encoder-decoder" tabindex="-1">Encoder/Decoder <a class="header-anchor" href="#encoder-decoder" aria-label="Permalink to &quot;Encoder/Decoder&quot;">​</a></h3><p>Encoder和Decoder是特殊的ChannelHandler，分别对应Outbound和Inbound的情况，Netty自带某些实现，其中<code>ByteToMessageDecoder</code>将byte流解析成对象(Message)，典型的如<code>ProtobufDecoder</code></p><p>注意，<strong>使用EventExecutorGroup来管理阻塞式的逻辑</strong></p><h2 id="channel" tabindex="-1">Channel <a class="header-anchor" href="#channel" aria-label="Permalink to &quot;Channel&quot;">​</a></h2><h3 id="功能" tabindex="-1">功能 <a class="header-anchor" href="#功能" aria-label="Permalink to &quot;功能&quot;">​</a></h3><ul><li>消息格式转换</li><li>异常通知</li><li>Channel状态变更(Active,Inactive)通知</li><li>Channel从EventLoop中注册/注销通知</li><li>自定义事件通知</li></ul><h3 id="多线程" tabindex="-1">多线程 <a class="header-anchor" href="#多线程" aria-label="Permalink to &quot;多线程&quot;">​</a></h3><h3 id="channel分类" tabindex="-1">Channel分类 <a class="header-anchor" href="#channel分类" aria-label="Permalink to &quot;Channel分类&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Name</th><th>Package</th><th>描述</th></tr></thead><tbody><tr><td>NIO</td><td>io.netty.channel.socket.nio</td><td>使用java.nio.channel</td></tr><tr><td>OIO</td><td>io.netty.channel.socket.oio</td><td>使用java.net包</td></tr><tr><td>Local</td><td>io.netty.channel.local</td><td>vm内部通信</td></tr><tr><td>Embedded</td><td>io.netty.channel.embedded</td><td>嵌入式，不依赖网络通信，适合测试</td></tr></tbody></table>',17)])])}const b=t(l,[["render",d]]);export{p as __pageData,b as default};
